(() => {
  const data = {
    "patientId": "MRN-100",
    "dischargeDate": "2026-07-08",
    "dischargeStatus": "Routine",
    "destination": "Home",
    "destinationAddress": "10 Demo Street",
    "livesAlone": false,
    "stairsAtHome": "None",
    "caregiverName": "Jordan Lee",
    "caregiverPhone": "555-123-4567",
    "caregiverRelationship": "Adult child",
    "caregiverAvailableOnDischarge": true,
    "transportType": "Self/Family",
    "medicationReconciliationComplete": true,
    "newMedications": "acetaminophen 500mg TID, oxycodone 5mg PRN breakthrough pain, omeprazole 20mg daily",
    "insuranceVerified": false,
    "followUpType": "Primary care",
    "followUpDate": "2026-07-15",
    "followUpBooked": true,
    "equipmentNeeded": ["None"],
    "homeHealthOrdered": false,
    "communityServicesReferral": false,
    "physicianSignature": true,
    "socialWorkerSignature": true
  };

  const setVal = (id, value) => {
    const el = document.getElementById(id);
    if (!el) return;
    if (el.type === 'checkbox') {
      if (el.checked !== value) {
        el.click();
      }
    } else if (el.tagName === 'SELECT') {
      el.value = value;
      el.dispatchEvent(new Event('change', { bubbles: true }));
    } else {
      let setter;
      if (el.tagName === 'TEXTAREA') {
        setter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
      } else {
        setter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set;
      }
      setter.call(el, value);
      el.dispatchEvent(new Event('input', { bubbles: true }));
      el.dispatchEvent(new Event('change', { bubbles: true }));
    }
  };

  for (const [key, value] of Object.entries(data)) {
    if (key === 'equipmentNeeded') {
      const equipSelect = document.getElementById(key);
      if (equipSelect) {
        Array.from(equipSelect.options).forEach(opt => {
          opt.selected = value.includes(opt.value);
        });
        equipSelect.dispatchEvent(new Event('change', { bubbles: true }));
      }
    } else {
      setVal(key, value);
    }
  }

  return "Done";
})()
